"use client";

/**
 * Admin / CRUD data-management dashboard — cold build on @gunjo/ui@0.0.1-alpha.2.
 *
 * Composition notes (black-box discovery):
 *  - ActionDataTable (display) is the workhorse: ColumnDef[] columns + data +
 *    rowActions + bulkActions + getRowId/getRowLabel + enableSelection. It owns
 *    selection state INTERNALLY (no controlled selectedIds / onSelectionChange),
 *    renders a select-all header checkbox with aria-checked="mixed", and renders
 *    its own bulk toolbar inside the table header (always present, disabled when
 *    nothing is selected — not an "appears on selection" bar).
 *  - It also inherits DataTable's single-column `filter` text box, sorting
 *    (enableSorting on a ColumnDef), and pagination. Custom cell renderers via
 *    ColumnDef.cell let us drop a <Badge> in for status.
 *  - rowActions render as inline icon Buttons, NOT a DropdownMenu, and there is
 *    no onRowClick. To get the required View/Edit/Delete row menu + row-click to
 *    open the editor, the action column is hand-rolled as a normal ColumnDef
 *    using DropdownMenu, instead of ActionDataTable's rowActions prop.
 */

import * as React from "react";
import type { ColumnDef } from "@gunjo/ui";
import {
  ActionDataTable,
  Badge,
  Button,
  Combobox,
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
  EmptyState,
  Input,
  Skeleton,
  Statistic,
  ToastProvider,
  useToast,
} from "@gunjo/ui";
import {
  IconDotsVertical,
  IconDownload,
  IconEye,
  IconInbox,
  IconPencil,
  IconPlus,
  IconTrash,
} from "@tabler/icons-react";

import { AdminShell, type NavKey } from "./AdminShell";
import { EditSubscriptionSheet } from "./EditSubscriptionSheet";
import {
  SUBSCRIPTIONS,
  STATUS_BADGE,
  STATUS_LABELS,
  formatDate,
  usd,
  type Subscription,
  type SubscriptionStatus,
} from "./data";

const STATUS_OPTIONS = [
  { value: "all", label: "すべてのステータス" },
  ...(Object.keys(STATUS_LABELS) as SubscriptionStatus[]).map((s) => ({
    value: s,
    label: STATUS_LABELS[s],
  })),
];

function AdminDashboard() {
  const { showToast } = useToast();

  const [nav, setNav] = React.useState<NavKey>("subscriptions");
  const [rows, setRows] = React.useState<Subscription[]>(SUBSCRIPTIONS);
  const [loading, setLoading] = React.useState(true);

  // Faceted filter state
  const [search, setSearch] = React.useState("");
  const [status, setStatus] = React.useState("all");
  const [renewsBefore, setRenewsBefore] = React.useState("");

  // Editor state
  const [editorOpen, setEditorOpen] = React.useState(false);
  const [editing, setEditing] = React.useState<Subscription | null>(null);

  // Simulate an initial fetch so the skeleton/loading state is exercised.
  React.useEffect(() => {
    const t = setTimeout(() => setLoading(false), 900);
    return () => clearTimeout(t);
  }, []);

  const filtered = React.useMemo(() => {
    const q = search.trim().toLowerCase();
    return rows.filter((r) => {
      if (status !== "all" && r.status !== status) return false;
      if (renewsBefore && r.renewsAt > renewsBefore) return false;
      if (
        q &&
        !r.customer.toLowerCase().includes(q) &&
        !r.email.toLowerCase().includes(q) &&
        !r.id.toLowerCase().includes(q)
      )
        return false;
      return true;
    });
  }, [rows, search, status, renewsBefore]);

  const kpis = React.useMemo(() => {
    const total = rows.length;
    const active = rows.filter((r) => r.status === "active").length;
    const mrr = rows.reduce((sum, r) => sum + r.mrr, 0);
    const pastDue = rows.filter((r) => r.status === "past_due").length;
    const churn = total ? (rows.filter((r) => r.status === "canceled").length / total) * 100 : 0;
    return { total, active, mrr, pastDue, churn };
  }, [rows]);

  const openEditor = React.useCallback((record: Subscription | null) => {
    setEditing(record);
    setEditorOpen(true);
  }, []);

  const handleSave = React.useCallback(
    (record: Subscription) => {
      setRows((prev) => {
        const exists = prev.some((r) => r.id === record.id);
        return exists
          ? prev.map((r) => (r.id === record.id ? record : r))
          : [record, ...prev];
      });
      setEditorOpen(false);
      showToast(
        rows.some((r) => r.id === record.id)
          ? `${record.customer} を保存しました`
          : `${record.customer} を作成しました`,
        "success"
      );
    },
    [rows, showToast]
  );

  const handleDelete = React.useCallback(
    (record: Subscription) => {
      setRows((prev) => prev.filter((r) => r.id !== record.id));
      showToast(`${record.customer} を削除しました`, "info");
    },
    [showToast]
  );

  const columns = React.useMemo<ColumnDef<Subscription>[]>(
    () => [
      {
        accessorKey: "customer",
        header: "顧客",
        enableSorting: true,
        size: 220,
        cell: ({ row }) => {
          const r = row.original;
          return (
            <button
              type="button"
              onClick={() => openEditor(r)}
              className="flex min-w-0 flex-col items-start rounded text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
            >
              <span className="truncate font-medium text-foreground">
                {r.customer}
              </span>
              <span className="truncate text-xs text-muted-foreground">
                {r.email}
              </span>
            </button>
          );
        },
      },
      {
        accessorKey: "plan",
        header: "プラン",
        size: 110,
        cell: ({ row }) => (
          <span className="text-sm">{row.original.plan}</span>
        ),
      },
      {
        accessorKey: "status",
        header: "ステータス",
        size: 120,
        cell: ({ row }) => {
          const s = row.original.status;
          return <Badge variant={STATUS_BADGE[s]}>{STATUS_LABELS[s]}</Badge>;
        },
      },
      {
        accessorKey: "seats",
        header: "シート数",
        enableSorting: true,
        size: 90,
        cell: ({ row }) => (
          <span className="tabular-nums">{row.original.seats}</span>
        ),
      },
      {
        accessorKey: "mrr",
        header: "月次収益",
        enableSorting: true,
        size: 110,
        cell: ({ row }) => (
          <span className="tabular-nums font-medium">
            {usd(row.original.mrr)}
          </span>
        ),
      },
      {
        accessorKey: "renewsAt",
        header: "更新日",
        enableSorting: true,
        size: 130,
        cell: ({ row }) => (
          <span className="whitespace-nowrap text-sm text-muted-foreground">
            {formatDate(row.original.renewsAt)}
          </span>
        ),
      },
      {
        id: "actions",
        header: () => <span className="sr-only">行の操作</span>,
        enableSorting: false,
        size: 64,
        cell: ({ row }) => {
          const r = row.original;
          return (
            <div className="flex justify-end">
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8"
                    aria-label={`${r.customer} の操作`}
                  >
                    <IconDotsVertical size={16} />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-40">
                  <DropdownMenuLabel>{r.id}</DropdownMenuLabel>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem
                    className="gap-2"
                    onSelect={() => openEditor(r)}
                  >
                    <IconEye size={16} /> 詳細を表示
                  </DropdownMenuItem>
                  <DropdownMenuItem
                    className="gap-2"
                    onSelect={() => openEditor(r)}
                  >
                    <IconPencil size={16} /> 編集
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem
                    className="gap-2 text-destructive focus:text-destructive"
                    onSelect={() => handleDelete(r)}
                  >
                    <IconTrash size={16} /> 削除
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          );
        },
      },
    ],
    [openEditor, handleDelete]
  );

  const hasFilters = search !== "" || status !== "all" || renewsBefore !== "";
  const clearFilters = () => {
    setSearch("");
    setStatus("all");
    setRenewsBefore("");
  };

  return (
    <AdminShell
      active={nav}
      onNavigate={setNav}
      search={search}
      onSearch={setSearch}
    >
      {/* Page heading */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-xl font-semibold tracking-tight sm:text-2xl">
            サブスクリプション
          </h1>
          <p className="text-sm text-muted-foreground">
            Aurora の全顧客の請求情報を管理します。
          </p>
        </div>
        <Button className="gap-2 self-start" onClick={() => openEditor(null)}>
          <IconPlus size={16} /> 新規サブスクリプション
        </Button>
      </div>

      {/* KPI row */}
      <section
        aria-label="主要指標"
        className="mt-5 grid grid-cols-2 gap-3 lg:grid-cols-4"
      >
        {loading ? (
          Array.from({ length: 4 }).map((_, i) => (
            <Skeleton key={i} className="h-[92px] w-full rounded-lg" />
          ))
        ) : (
          <>
            <Statistic
              label="総サブスクリプション数"
              value={kpis.total.toLocaleString()}
              change="今月 +4件"
              trend="up"
            />
            <Statistic
              label="有効"
              value={kpis.active.toLocaleString()}
              change={`全体の ${Math.round((kpis.active / kpis.total) * 100)}%`}
              trend="up"
            />
            <Statistic
              label="月次経常収益"
              value={usd(kpis.mrr)}
              change="+12.4%"
              trend="up"
            />
            <Statistic
              label="解約率"
              value={`${kpis.churn.toFixed(1)}%`}
              change={`支払い遅延 ${kpis.pastDue}件`}
              trend={kpis.churn > 15 ? "down" : "flat"}
              tone={kpis.churn > 15 ? "negative" : "neutral"}
            />
          </>
        )}
      </section>

      {/* Faceted filters */}
      <section
        aria-label="フィルター"
        className="mt-6 flex flex-col gap-3 rounded-lg border bg-card p-3 sm:flex-row sm:items-end"
      >
        <div className="flex flex-col gap-1.5">
          <label htmlFor="filter-search" className="text-xs font-medium text-muted-foreground">
            検索
          </label>
          <Input
            id="filter-search"
            value={search}
            placeholder="顧客名・メール・ID"
            onChange={(e) => setSearch(e.target.value)}
            className="sm:w-56"
          />
        </div>
        <div className="flex flex-col gap-1.5">
          <span className="text-xs font-medium text-muted-foreground">ステータス</span>
          <Combobox
            options={STATUS_OPTIONS}
            value={status}
            onValueChange={(v) => setStatus(v || "all")}
            placeholder="すべてのステータス"
            className="sm:w-48"
          />
        </div>
        <div className="flex flex-col gap-1.5">
          <label htmlFor="filter-renews" className="text-xs font-medium text-muted-foreground">
            更新日（指定日以前）
          </label>
          <Input
            id="filter-renews"
            type="date"
            value={renewsBefore}
            onChange={(e) => setRenewsBefore(e.target.value)}
            className="sm:w-44"
          />
        </div>
        {hasFilters ? (
          <Button
            variant="ghost"
            onClick={clearFilters}
            className="self-start sm:ml-auto sm:self-auto"
          >
            フィルターをクリア
          </Button>
        ) : null}
      </section>

      {/* Table / states */}
      <section aria-label="サブスクリプション一覧" className="mt-4">
        {loading ? (
          <div className="space-y-2 rounded-lg border p-4">
            {Array.from({ length: 6 }).map((_, i) => (
              <Skeleton key={i} className="h-10 w-full" />
            ))}
          </div>
        ) : filtered.length === 0 ? (
          <EmptyState
            icon={<IconInbox size={22} />}
            title="条件に一致するサブスクリプションがありません"
            description="検索キーワード、ステータス、更新日を変更してお試しください。"
            action={
              <Button variant="outline" onClick={clearFilters}>
                フィルターをクリア
              </Button>
            }
          />
        ) : (
          <ActionDataTable<Subscription, unknown>
            data={filtered}
            columns={columns}
            // FINDING: ActionDataTable/DataTable logs "[Table] Column with id ''
            // does not exist" unless `filter` is explicitly null. The prop is
            // optional but its default (undefined) is not treated as "off".
            filter={null}
            getRowId={(r) => r.id}
            getRowLabel={(r) => r.customer}
            labels={{
              selectedRowsLabel: "件を選択中",
              bulkActionPlaceholder: "一括操作",
            }}
            bulkActions={[
              {
                id: "export",
                label: "エクスポート",
                icon: IconDownload,
                variant: "outline",
                onSelect: (selected) =>
                  showToast(`${selected.length}件をエクスポートしました`, "success"),
              },
              {
                id: "delete",
                label: "削除",
                icon: IconTrash,
                variant: "destructive",
                onSelect: (selected) => {
                  const ids = new Set(selected.map((s) => s.id));
                  setRows((prev) => prev.filter((r) => !ids.has(r.id)));
                  showToast(`${selected.length}件を削除しました`, "info");
                },
              },
            ]}
          />
        )}
      </section>

      <EditSubscriptionSheet
        record={editing}
        open={editorOpen}
        onOpenChange={setEditorOpen}
        onSave={handleSave}
      />
    </AdminShell>
  );
}

export default function AdminPage() {
  return (
    <ToastProvider>
      <AdminDashboard />
    </ToastProvider>
  );
}

