"use client";

import * as React from "react";
import {
  Button,
  Form,
  FormField,
  FormGroup,
  FormLabel,
  FormDescription,
  Input,
  Select,
  Switch,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  SheetClose,
} from "@gunjo/ui";
import {
  PLANS,
  STATUS_LABELS,
  type Plan,
  type Subscription,
  type SubscriptionStatus,
} from "./data";

export interface EditSubscriptionSheetProps {
  /** The record to edit, or null for "create new". */
  record: Subscription | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSave: (record: Subscription) => void;
}

const STATUSES = Object.keys(STATUS_LABELS) as SubscriptionStatus[];

const blank = (): Subscription => ({
  id: `sub_${Math.floor(Math.random() * 9000 + 1000)}`,
  customer: "",
  email: "",
  plan: "Starter",
  status: "trialing",
  seats: 1,
  mrr: 0,
  createdAt: new Date().toISOString().slice(0, 10),
  renewsAt: new Date(Date.now() + 14 * 864e5).toISOString().slice(0, 10),
  region: "NA",
});

export function EditSubscriptionSheet({
  record,
  open,
  onOpenChange,
  onSave,
}: EditSubscriptionSheetProps) {
  const [draft, setDraft] = React.useState<Subscription>(blank);

  // Re-seed the form whenever a different record is opened.
  React.useEffect(() => {
    if (open) setDraft(record ? { ...record } : blank());
  }, [open, record]);

  const isNew = record === null;
  const set = <K extends keyof Subscription>(key: K, value: Subscription[K]) =>
    setDraft((d) => ({ ...d, [key]: value }));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(draft);
  };

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="right"
        className="flex w-full max-w-md flex-col gap-0 sm:max-w-md"
      >
        <SheetHeader>
          <SheetTitle>
            {isNew ? "新規サブスクリプション" : `${record?.customer} を編集`}
          </SheetTitle>
          <SheetDescription>
            {isNew
              ? "サブスクリプションを新規作成します。保存時に入力内容を検証します。"
              : `${record?.email} の請求情報を更新します。`}
          </SheetDescription>
        </SheetHeader>

        <Form
          id="edit-subscription-form"
          onSubmit={handleSubmit}
          className="flex-1 overflow-y-auto px-1 py-4"
        >
          <FormField className="p-0">
            <FormGroup>
              <FormLabel htmlFor="f-customer">顧客名</FormLabel>
              <Input
                id="f-customer"
                value={draft.customer}
                required
                placeholder="株式会社サンプル"
                onChange={(e) => set("customer", e.target.value)}
              />
            </FormGroup>
          </FormField>

          <FormField className="p-0">
            <FormGroup>
              <FormLabel htmlFor="f-email">請求先メールアドレス</FormLabel>
              <Input
                id="f-email"
                type="email"
                value={draft.email}
                required
                placeholder="billing@example.co.jp"
                onChange={(e) => set("email", e.target.value)}
              />
            </FormGroup>
          </FormField>

          <div className="grid grid-cols-2 gap-3">
            <FormField className="p-0">
              <FormGroup>
                <FormLabel htmlFor="f-plan">プラン</FormLabel>
                <Select
                  id="f-plan"
                  value={draft.plan}
                  onChange={(e) => set("plan", e.target.value as Plan)}
                >
                  {PLANS.map((p) => (
                    <option key={p} value={p}>
                      {p}
                    </option>
                  ))}
                </Select>
              </FormGroup>
            </FormField>

            <FormField className="p-0">
              <FormGroup>
                <FormLabel htmlFor="f-status">ステータス</FormLabel>
                <Select
                  id="f-status"
                  value={draft.status}
                  onChange={(e) =>
                    set("status", e.target.value as SubscriptionStatus)
                  }
                >
                  {STATUSES.map((s) => (
                    <option key={s} value={s}>
                      {STATUS_LABELS[s]}
                    </option>
                  ))}
                </Select>
              </FormGroup>
            </FormField>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <FormField className="p-0">
              <FormGroup>
                <FormLabel htmlFor="f-seats">シート数</FormLabel>
                <Input
                  id="f-seats"
                  type="number"
                  min={1}
                  value={draft.seats}
                  onChange={(e) => set("seats", Number(e.target.value))}
                />
              </FormGroup>
            </FormField>

            <FormField className="p-0">
              <FormGroup>
                <FormLabel htmlFor="f-mrr">月次経常収益（円）</FormLabel>
                <Input
                  id="f-mrr"
                  type="number"
                  min={0}
                  value={draft.mrr}
                  onChange={(e) => set("mrr", Number(e.target.value))}
                />
              </FormGroup>
            </FormField>
          </div>

          <FormField className="p-0">
            <FormGroup>
              <FormLabel htmlFor="f-renews">次回更新日</FormLabel>
              <Input
                id="f-renews"
                type="date"
                value={draft.renewsAt}
                onChange={(e) => set("renewsAt", e.target.value)}
              />
              <FormDescription>
                このサブスクリプションの次回自動請求日です。
              </FormDescription>
            </FormGroup>
          </FormField>

          <FormField className="p-0">
            <div className="flex items-center justify-between rounded-lg border border-border p-3">
              <div className="flex flex-col">
                <FormLabel htmlFor="f-autorenew">自動更新</FormLabel>
                <FormDescription>
                  更新時に登録済みのカードへ請求します。
                </FormDescription>
              </div>
              <Switch
                id="f-autorenew"
                aria-label="自動更新"
                checked={draft.status !== "canceled"}
                onCheckedChange={(on) =>
                  set("status", on ? "active" : "canceled")
                }
              />
            </div>
          </FormField>
        </Form>

        <SheetFooter className="mt-auto flex-row justify-end gap-2 border-t pt-4">
          <SheetClose asChild>
            <Button variant="outline" type="button">
              キャンセル
            </Button>
          </SheetClose>
          <Button type="submit" form="edit-subscription-form">
            {isNew ? "作成" : "変更を保存"}
          </Button>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}
